temp_files.zz_eval_lazy_jobs_test.mbt:
///|
test "grader does no work when constructing the iterator" {
  let log : Array[String] = []
  ignore(planned_jobs(log))
  assert_eq(log, [])
}

///|
test "grader prepares only the first demanded item" {
  let log : Array[String] = []
  assert_eq(planned_jobs(log).take(1).collect(), [10])
  assert_eq(log, ["prepare 10"])
}

///|
test "grader prepares exactly a longer demanded prefix" {
  let log : Array[String] = []
  assert_eq(planned_jobs(log).take(2).collect(), [10, 20])
  assert_eq(log, ["prepare 10", "prepare 20"])
}

///|
test "grader preserves full values and preparation order" {
  let log : Array[String] = []
  assert_eq(planned_jobs(log).collect(), [10, 20, 30])
  assert_eq(log, ["prepare 10", "prepare 20", "prepare 30"])
}
